// Compliant: Strong encryption keys
#include <openssl/rsa.h>
#include <random>

void strongEncryption() {
    RSA* rsa = RSA_new();
    BIGNUM* bn = BN_new();
    BN_set_word(bn, RSA_F4);

    // 2048-bit or higher key
    RSA_generate_key_ex(rsa, 2048, bn, nullptr);
}

// Compliant: Generated secure key
std::string generateSecureKey(size_t length) {
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_int_distribution<> dis(0, 255);

    std::string key;
    key.reserve(length);
    for (size_t i = 0; i < length; ++i) {
        key += static_cast<char>(dis(gen));
    }
    return key;
}
